require "data.GameArea"

SafeAreaConfig = {}
SafeAreaConfig.SafeAreas = {}
SafeAreaConfig.AreaTree = {}
SafeAreaConfig.CurLevel = 0
SafeAreaConfig.Areas = {}

function SafeAreaConfig:init(config)
    RandomUtil:setRandomSeed()
    local data = {}
    for _, safeArea in pairs(config) do
        local item = {}
        item.id = tonumber(safeArea.id)
        item.area1 = tonumber(safeArea.area1)
        item.area2 = StringUtil.split(safeArea.area2, "#")
        item.area3 = StringUtil.split(safeArea.area3, "#")
        item.area4 = StringUtil.split(safeArea.area4, "#")
        item.area5 = StringUtil.split(safeArea.area5, "#")
        item.area6 = StringUtil.split(safeArea.area6, "#")
        self.SafeAreas[item.id] = item
        table.insert(data, item.id)
    end
    RandomUtil:initRandomSeed("area1", data)
    self:randomSafeArea()
end

function SafeAreaConfig:randomSafeArea()
    local id = RandomUtil:get("area1")
    local area = self.SafeAreas[id]
    if next(area) == nil then
        area = self.SafeAreas[1]
    end
    table.insert(self.AreaTree, area.area1)
    local config = AreaConfig:getAreaById(tonumber(area.area1))
    self.Areas[area.area1] = GameArea.new(config)

    for i = 2, 6 do
        local remark = "area" .. i
        if next(area[remark]) == nil then
            break
        end
        AreaConfig:initRandomArea(area[remark], remark)
    end

    self:setSafeTree(area)
end

function SafeAreaConfig:setSafeTree(areas)
    for i = 2, 6 do
        local remark = "area" .. i
        if next(areas[remark]) == nil then
            break
        end

        local index = RandomUtil:get(remark)
        local id = areas[remark][index]
        local area = AreaConfig:getAreaById(tonumber(id))
        local lastArea = self.AreaTree[#(self.AreaTree)]
        while area == nil or not self:isInArea(area, lastArea) do
            index = RandomUtil:get(remark)
            id = areas[remark][index]
            area = AreaConfig:getAreaById(tonumber(id))
        end
        self.Areas[id] = GameArea.new(area)
        table.insert(self.AreaTree, id)
    end
end

function SafeAreaConfig:creatSafeArea()
    local poison = {}
    local safe = {}
    if self.CurLevel > 0 then
        local pId = self.AreaTree[self.CurLevel]
        poison = self.Areas[pId]
    end

    if SafeAreaConfig:isLastArea() then
        local area = SafeAreaConfig:getCurArea()
        local center = area:getCenter()
        safe = {
            startPos = center,
            endPos = center
        }
        self.CurLevel = self.CurLevel + 1
    else
        self.CurLevel = self.CurLevel + 1
        local sId = self.AreaTree[self.CurLevel]
        safe = AreaConfig:getAreaById(tonumber(sId))
    end
    return safe, poison
end

function SafeAreaConfig:getWaitCreatTime()
    local id = self.AreaTree[self.CurLevel + 1]
    if id == nil then
        return 0
    end
    local nextArea = AreaConfig:getAreaById(id)
    if (nextArea ~= nil) then
        return nextArea.waitCreatTime
    end
    return 0
end

function SafeAreaConfig:getWaitShrinkTime()
    local id = self.AreaTree[self.CurLevel]
    if id == nil then
        return 0
    end
    local area = AreaConfig:getAreaById(id)
    if (area ~= nil) then
        return area.waitShrinkTime
    end
    return 0
end

function SafeAreaConfig:isInArea(area, lastArea)
    if tonumber(area.fatherArea) == 0 then
        return true
    end
    for _, father in pairs(area.fatherArea) do
        if tonumber(father) == tonumber(lastArea) then
            return true
        end
    end
    return false
end

function SafeAreaConfig:isLastArea()
    local id = self.AreaTree[self.CurLevel + 1]
    if id == nil then
        return true
    end
    local area = AreaConfig:getAreaById(id)
    if (area ~= nil) then
        return false
    end
    return true
end

function SafeAreaConfig:getCurArea()
    local level = self.CurLevel
    if level == 0 then
        level = 1
    end
    local sId = self.AreaTree[level]
    local safe = self.Areas[sId]
    return safe
end

function SafeAreaConfig:getCurAreaId()
    local level = self.CurLevel
    if level == 0 then
        level = 1
    end
    local sId = self.AreaTree[level]
    return sId
end

function SafeAreaConfig:getSpeed(area1, area2, time)
    local distance = math.max(area1.startPos.x - area2.startPos.x, area1.startPos.y - area2.startPos.y,
            area1.startPos.z - area2.startPos.z, area2.endPos.x - area1.endPos.x, area2.endPos.y - area1.endPos.y,
            area2.endPos.z - area1.endPos.z)
    return distance / time
end

function SafeAreaConfig:isLastPoison()
    local id = self.AreaTree[self.CurLevel]
    if id == nil then
        return true
    end
    local area = AreaConfig:getAreaById(id)
    if (area ~= nil) then
        return false
    end
    return true
end